51	- (instancetype)init {
52	    self = [super init];
53	    if (self) {
54	        DLogTagInfo(kBLEParkingTag, @"泊车调试 XPAutoParkingViewModel init");
55	
56	        _isTimerRunningFlag = 0;
57	        _cancelTimerSignal = [RACSubject subject];
58	        @weakify(self);
59	        [[XPBLEHandlerManager.manager.sendBleConnectStateSingal.deliverOnMainThread takeUntil:self.rac_willDeallocSignal] subscribeNext:^(NSNumber*  _Nullable x) {
60	            @strongify(self)
61	
62	            NSDictionary *stateDict = (NSDictionary *)x;
63	            XPBLEHanderConnectState state = [stateDict[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
64	            BOOL isCommunicate = [stateDict[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
65	            if (XPBLEHanderConnectStateAuthorized != state && isCommunicate) {
66	                DLogTagError(kBLEParkingTag, @"蓝牙断开。目前状态是%@",x);
67	                [self updateIsAuthorized:NO];
68	            }
69	            
70	        }];
71	        
72	        [[self.startTimerCommand.executing takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeNext:^(NSNumber * _Nullable x) {
73	            @strongify(self)
74	            if (x.boolValue) {
75	                [self markTimerStart];
76	            } else {
77	                [self markTimerExit];
78	                [self updateIsAuthorized:NO];
79	            }
80	        }];
81	    }
82	    
83	    // E28
84	    [self.rac_deallocDisposable addDisposable:[[XPBLEDataHanderManager.instance.bleExceptionResultSubject takeUntil:self.rac_willDeallocSignal]  subscribeNext:^(NSDictionary *  _Nullable info) {
85	        DLogTagInfo(kBLEParkingTag, @"泊车调试 泊车收到bleMessage %@", info);
86	        int errorCode = [[info valueForKey:@"bleExceptionResult"] intValue];
87	        if (errorCode != 0) {
88	            NSError * x = [NSError errorWithDomain:@"XPCarControlErrorDomain" code:XPCarControlErrorCodeBleExecFailed userInfo:@{NSLocalizedFailureReasonErrorKey:[info valueForKey:@"bleExceptionResult"] ?: @"Unknown", @"code": @(errorCode)}];
89	
90	            [[NSNotificationCenter defaultCenter] postNotificationName:ParkingBLEKeyExceptionNotification object:nil userInfo:@{@"error" : x}];
91	        }
92	    }]];
93	    
94	    // D55
95	    [self.rac_deallocDisposable addDisposable:[[XPBLEDataHanderManager.instance.bleControlEventSubject takeUntil:self.rac_willDeallocSignal]  subscribeNext:^(NSDictionary *  _Nullable info) {
96	        DLogTagInfo(kBLEParkingTag, @"泊车调试 泊车收到车控结果 %@", info);
97	        int errorCode = [[info valueForKey:@"bleControlEventResult"] intValue];
98	        if (errorCode != 0) {
99	            NSError * x = [NSError errorWithDomain:@"XPCarControlErrorDomain" code:XPCarControlErrorCodeBleExecFailed userInfo:@{NSLocalizedFailureReasonErrorKey:[info valueForKey:@"bleControlEventId"] ?: @"Unknown", @"code": @(errorCode)}];
100	
101	            [[NSNotificationCenter defaultCenter] postNotificationName:ParkingBLEKeyExceptionNotification object:nil userInfo:@{@"error" : x}];
102	        }
103	
104	    }]];
105	
106	    
107	    return self;
108	}
