139	- (void)waitingForBiometricResults {
140	    @weakify(self)
141	    RACCompoundDisposable* dispose = [RACCompoundDisposable compoundDisposable];
142	    RACDisposable* d = [[[[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
143	        @strongify(self)
144	        DLogTagInfo(kBLEParkingTag, @"泊车调试 泊车注册事件消息");
145	
146	        return [RACCompoundDisposable compoundDisposableWithDisposables:@[
147	            [XPBLEHandlerManager.manager.sendBleConnectStateSingal subscribeNext:^(NSNumber* _Nullable x) {
148	            NSDictionary *stateDict = (NSDictionary *)x;
149	            XPBLEHanderConnectState state = [stateDict[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
150	            BOOL isCommunicate = [stateDict[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
151	            if (!isCommunicate) {
152	                return;
153	            }
154	
155	            if (XPBLEHanderConnectStateAuthorized != state) {
156	                DLogTagInfo(kBLEParkingTag, @"蓝牙连接断开,生物认证中断");
157	                NSError* err = [NSError errorWithDomain:@"com.xiaopeng.XPAutoParkingViewModel"
158	                                                   code:-1
159	                                               userInfo:@{NSLocalizedFailureReasonErrorKey:@"蓝牙连接断开,生物认证中断"}];
160	                [subscriber sendError:err];
161	            }
162	        }],
163	            
164	            [[NSNotificationCenter.defaultCenter rac_addObserverForName:UIApplicationDidEnterBackgroundNotification object:nil].deliverOnMainThread subscribeNext:^(NSNotification * _Nullable x) {
165	                DLogTagInfo(kBLEParkingTag, @"App正转让后台,生物认证中断");
166	                NSError* err = [NSError errorWithDomain:@"com.xiaopeng.XPAutoParkingViewModel"
167	                                                   code:-1
168	                                               userInfo:@{NSLocalizedFailureReasonErrorKey:@"App正转让后台,生物认证中断"}];
169	                [subscriber sendError:err];
170	            }],
171	            
172	            [[NSNotificationCenter.defaultCenter rac_addObserverForName:UIApplicationWillResignActiveNotification object:nil].deliverOnMainThread subscribeNext:^(NSNotification * _Nullable x) {
173	                DLogTagInfo(kBLEParkingTag, @"App状态正要变为Resign Active,生物认证中断");
174	                NSError* err = [NSError errorWithDomain:@"com.xiaopeng.XPAutoParkingViewModel"
175	                                                   code:-1
176	                                               userInfo:@{NSLocalizedFailureReasonErrorKey:@"App状态正要变为Resign Active,生物认证中断"}];
177	                [subscriber sendError:err];
178	            }],
179	            
180	            [[XPCallCenter.shareInstance.stateSignal takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeNext:^(NSString * _Nullable x) {
181	                DLogTagInfo(kBLEParkingTag, @"电话打入,生物认证中断");
182	                NSError* err = [NSError errorWithDomain:@"com.xiaopeng.XPAutoParkingViewModel"
183	                                                   code:-1
184	                                               userInfo:@{NSLocalizedFailureReasonErrorKey:@"电话打入，生物认证中断"}];
185	                [subscriber sendError:err];
186	            }],
187	            
188	            [[XPBLEDataHanderManager.instance.bleExceptionResultSubject takeUntil:self.rac_willDeallocSignal] subscribeNext:^(NSDictionary *  _Nullable info) {
189	                DLogTagInfo(kBLEParkingTag, @"泊车调试 泊车收到bleMessageSubject结果");
190	                if ([info valueForKey:BLE_EXCEPTION_RESULT_KEY]) {
191	                    NSError* err = [NSError errorWithDomain:@"com.xiaopeng.XPAutoParkingViewModel"
192	                                                       code:1001
193	                                                   userInfo:@{NSLocalizedFailureReasonErrorKey:@"蓝牙控制异常"}];
194	                    [subscriber sendError:err];
195	                }
196	            }],
197	            
198	            [XPBLEDataHanderManager.instance.bleControlEventSubject  subscribeNext:^(NSDictionary *  _Nullable info) {
199	                DLogTagInfo(kBLEParkingTag, @"泊车调试 泊车收到车控结果");
200	                if ([info valueForKey:BLE_EXCEPTION_RESULT_KEY]) {
201	                }
202	            }]
203	
204	        ]];
205	    }] timeout:0.1 onScheduler:[RACScheduler schedulerWithPriority:RACSchedulerPriorityHigh]].deliverOnMainThread catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
206	        if ([error.domain isEqualToString:RACSignalErrorDomain] && RACSignalErrorTimedOut == error.code) {
207	            return [RACSignal empty];
208	        } else {
209	            return [RACSignal error:error];
210	        }
211	    }] subscribeError:^(NSError * _Nullable error) {
212	        __IF_DO(![dispose isDisposed], [dispose dispose])
213	        [self updateIsAuthorized:NO];
214	        if (![NSString isEmptyWithString:error.localizedFailureReason]) {
215	            [XPToast showMessage:error.localizedFailureReason];
216	        }
217	        DLogTagError(kBLEParkingTag, @"%@",error);
218	    } completed:^{
219	        __IF_DO(![dispose isDisposed], [dispose dispose])
220	        [self updateIsAuthorized:YES];
221	        self.hasAuthorized = YES;
222	    }];
223	    
224	    [dispose addDisposable:d];
225	    
226	}
