239	- (void)sendSafeKeyVerifyCommand:(XPTBoxCommand)cmd {
240	    if (!XPBLEKeyManager.instance.defaultCard.isValid) {
241	        DLogTagWarn(kBLEKeyTag, @"%@不是在当次安装中注册的", XPBLEKeyManager.instance.defaultCard);
242	        //        [XPToast showMessage:@"无有效钥匙"];
243	    }
244	    __CHECK(XPBLEKeyManager.instance.defaultCard.isValid)
245	    if ([XPBLEHandlerManager.manager commuicateBleIsSendingBleCommand] && CTMediator.isE28) {
246	        DLogTagWarn(kBLEKeyTag, @"当前正在发送蓝牙车控指令,直接返回不做处理");
247	        return;
248	    }
249	    @weakify(self)
250	    [[[XPBLEKeyManager.instance.getTokenCommand execute:XPBLEKeyManager.instance.defaultCard.cardNo].deliverOnMainThread takeUntil:self.rac_willDeallocSignal] subscribeError:^(NSError * _Nullable error) {
251	        DLogTagError(kBLEKeyTag, @"获取认证token失败,error=%@", error);
252	        if([error.domain isEqualToString:@"com.xiaopeng.EtasGetAuthDataSession"] && error.code == ERR_IFAA_DEVICE_NOT_REGISTERED){
253	            [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_delete_key", nil)];
254	        }
255	    } completed:^{
256	        DLogTagInfo(kBLEKeyTag, @"获取认证token成功，准备发送认证命令");
257	        if (cmd == XPTBoxCommandParking) {
258	            [EtasManager skipBioAuth:YES];
259	        }
260	        [[[XPBLEKeyManager.instance.verifyCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeNext:^(NSString*  _Nullable ifaaMsg) {
261	            DLogTagError_if([NSString isEmptyWithString:ifaaMsg], kBLEKeyTag, @"ifaaMsg is nil");
262	            __CHECK(![NSString isEmptyWithString:ifaaMsg])
263	            @strongify(self)
264	            [XPBLEHandlerManager.manager sendRkeControlIFFAMessage:@{@"ifaa":ifaaMsg,@"cmd":@(cmd)} complete:^(NSError * _Nullable error) {
265	                if (error) {
266	                    DLogTagError(kBLEKeyTag, @"%@",error);
267	                    [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_back_to_homepage_tip", nil)];
268	                } else {
269	                    DLogTagInfo(kBLEKeyTag, @"send ble command success");
270	                    [self waitingForBiometricResults];
271	                }
272	            }];
273	            
274	        } error:^(NSError * _Nullable error) {
275	            
276	            DLogTagError(kBLEKeyTag, @"认证命令失败,error=%@",error);
277	            if (ERR_REMAIN_IFAA_AUTH_DATACOUNT_EMPTY == error.code) {
278	                @strongify(self)
279	                [[[XPBLEKeyManager.instance.getAuthDataCommand execute:XPBLEKeyManager.instance.defaultCard.cardNo] takeUntil:self.rac_willDeallocSignal] subscribeError:^(NSError * _Nullable error) {
280	                    DLogTagError(kBLEKeyTag, @"%@",error);
281	                    [XPToast showMessage:error.localizedFailureReason];
282	                } completed:^{
283	                    DLogTagInfo(kBLEKeyTag, @"getAuthData success");
284	                    [self sendVerifyCommand:cmd];
285	                }];
286	            } else {
287	                if (![NSString isEmptyWithString:error.localizedFailureReason]) {
288	                    DLogTagError(kBLEKeyTag, [NSString stringWithFormat:@"本地验证失败:%@",error.localizedFailureReason]);
289	                    [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_Authentication_failed", nil)];
290	                }
291	            }
292	        }];
293	    }];
294	}
