365	- (RACCommand*)startTimerCommand {
366	    if (nil == _startTimerCommand) {
367	        @weakify(self)
368	        _startTimerCommand = [[RACCommand alloc] initWithSignalBlock:^RACSignal * _Nonnull(id  _Nullable input) {
369	            return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
370	                @strongify(self)
371	                self.heartBeatCount = 0x0;
372	                RACScheduler* scheduler = [RACScheduler schedulerWithPriority:DISPATCH_QUEUE_PRIORITY_HIGH];
373	                RACCompoundDisposable* dispose = [RACCompoundDisposable compoundDisposableWithDisposables:@[
374	                    [[RACSignal interval:0.15 onScheduler:scheduler] subscribeNext:^(NSDate * _Nullable x) {
375	                        DLogTagDebug(kBLEParkingTag, @"蓝牙泊车心跳器运行中");
376	                        const uint64_t c = [self heartBeat];
377	                        [subscriber sendNext:@(c)];
378	                    }],
379	                    [XPBLEHandlerManager.manager.sendBleConnectStateSingal subscribeNext:^(NSNumber* _Nullable x) {
380	                    NSDictionary *stateDict = (NSDictionary *)x;
381	                    XPBLEHanderConnectState state = [stateDict[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
382	                    BOOL isCommunicate = [stateDict[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
383	                    if (!isCommunicate) {
384	                        return;
385	                    }
386	                    if (XPBLEHanderConnectStateAuthorized != state) {
387	                        DLogTagInfo(kBLEParkingTag, @"泊车心跳计时器退出");
388	                        [subscriber sendCompleted];
389	                    }
390	                }],
391	                    
392	                    [self.vcDeallocSignal subscribeCompleted:^{
393	                        DLogTagInfo(kBLEParkingTag, @"泊车心跳计时器退出");
394	                        [subscriber sendCompleted];
395	                    }],
396	                    
397	//                    [[NSNotificationCenter.defaultCenter rac_addObserverForName:UIApplicationDidEnterBackgroundNotification object:nil] subscribeNext:^(NSNotification * _Nullable x) {
398	//                        DLogTagInfo(kBLEParkingTag, @"泊车心跳计时器退出");
399	//                        [subscriber sendCompleted];
400	//                    }],
401	//
402	//                    [[NSNotificationCenter.defaultCenter rac_addObserverForName:UIApplicationWillResignActiveNotification object:nil] subscribeNext:^(NSNotification * _Nullable x) {
403	//                        DLogTagInfo(kBLEParkingTag, @"泊车心跳计时器退出");
404	//                        [subscriber sendCompleted];
405	//                    }],
406	
407	//                    [[XPCallCenter.shareInstance.stateSignal takeUntil:self.rac_willDeallocSignal] subscribeNext:^(NSString * _Nullable x) {
408	//                        DLogTagInfo(kBLEParkingTag, @"泊车心跳计时器退出");
409	//                        [subscriber sendCompleted];
410	//                    }],
411	
412	                    [self.cancelTimerSignal subscribeNext:^(id  _Nullable x) {
413	                        DLogTagInfo(kBLEParkingTag, @"泊车心跳计时器退出");
414	                        [subscriber sendCompleted];
415	                    }],
416	                ]];
417	                return [RACDisposable disposableWithBlock:^{
418	                    DLogTagInfo(kBLEParkingTag, @"泊车心跳计时器退出");
419	                    [dispose dispose];
420	                    [subscriber sendCompleted];
421	                }];
422	            }];
423	        }];
424	    }
425	    
426	    return _startTimerCommand;
427	}
