434	- (uint64_t)heartBeat {
435	    if (OSAtomicCompareAndSwap64Barrier(0x7F, 0x0, &_heartBeatCount)) {
436	        return _heartBeatCount;
437	    }
438	
439	    return OSAtomicIncrement64Barrier(&_heartBeatCount);
440	}
