456	+ (void)sendQuickBeat{
457	    __CHECK([XPBLEHandlerManager.manager getCommuicateBLEConnectState] == XPBLEHanderConnectStateAuthorized)
458	    XPBLEParkingCommand cmd = XPBLEParkingCommandStop;
459	    [XPBLEHandlerManager.manager sendBleParkingHeartMessage:@{@"cmd":@(cmd),@"count":@(0)} complete:^(NSError * _Nullable error) {
460	        if (error) {
