- (void)sendSafeKeyVerifyCommand:(XPTBoxCommand)cmd {
    if (!XPBLEKeyManager.instance.defaultCard.isValid) {
        DLogTagWarn(kBLEKeyTag, @"%@不是在当次安装中注册的", XPBLEKeyManager.instance.defaultCard);
        //        [XPToast showMessage:@"无有效钥匙"];
    }
    __CHECK(XPBLEKeyManager.instance.defaultCard.isValid)
    if ([XPBLEHandlerManager.manager commuicateBleIsSendingBleCommand] && CTMediator.isE28) {
        DLogTagWarn(kBLEKeyTag, @"当前正在发送蓝牙车控指令,直接返回不做处理");
        return;
    }
    @weakify(self)
    [[[XPBLEKeyManager.instance.getTokenCommand execute:XPBLEKeyManager.instance.defaultCard.cardNo].deliverOnMainThread takeUntil:self.rac_willDeallocSignal] subscribeError:^(NSError * _Nullable error) {
        DLogTagError(kBLEKeyTag, @"获取认证token失败,error=%@", error);
        if([error.domain isEqualToString:@"com.xiaopeng.EtasGetAuthDataSession"] && error.code == ERR_IFAA_DEVICE_NOT_REGISTERED){
            [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_delete_key", nil)];
        }
    } completed:^{
        DLogTagInfo(kBLEKeyTag, @"获取认证token成功，准备发送认证命令");
        if (cmd == XPTBoxCommandParking) {
            [EtasManager skipBioAuth:YES];
        }
        [[[XPBLEKeyManager.instance.verifyCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeNext:^(NSString*  _Nullable ifaaMsg) {
            DLogTagError_if([NSString isEmptyWithString:ifaaMsg], kBLEKeyTag, @"ifaaMsg is nil");
            __CHECK(![NSString isEmptyWithString:ifaaMsg])
            @strongify(self)
            [XPBLEHandlerManager.manager sendRkeControlIFFAMessage:@{@"ifaa":ifaaMsg,@"cmd":@(cmd)} complete:^(NSError * _Nullable error) {
                if (error) {
                    DLogTagError(kBLEKeyTag, @"%@",error);
                    [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_back_to_homepage_tip", nil)];
                } else {
                    DLogTagInfo(kBLEKeyTag, @"send ble command success");
                    [self waitingForBiometricResults];
                }
            }];

        } error:^(NSError * _Nullable error) {

            DLogTagError(kBLEKeyTag, @"认证命令失败,error=%@",error);
            if (ERR_REMAIN_IFAA_AUTH_DATACOUNT_EMPTY == error.code) {
                @strongify(self)
                [[[XPBLEKeyManager.instance.getAuthDataCommand execute:XPBLEKeyManager.instance.defaultCard.cardNo] takeUntil:self.rac_willDeallocSignal] subscribeError:^(NSError * _Nullable error) {
                    DLogTagError(kBLEKeyTag, @"%@",error);
                    [XPToast showMessage:error.localizedFailureReason];
                } completed:^{
                    DLogTagInfo(kBLEKeyTag, @"getAuthData success");
                    [self sendVerifyCommand:cmd];
                }];
            } else {
                if (![NSString isEmptyWithString:error.localizedFailureReason]) {
                    DLogTagError(kBLEKeyTag, [NSString stringWithFormat:@"本地验证失败:%@",error.localizedFailureReason]);
                    [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_Authentication_failed", nil)];
                }
            }
        }];
    }];
}

- (void)sendCertKeyVerifyCommand:(XPTBoxCommand)cmd {
    if (![XPBLEKeyManager.instance isSafeKeyOrCertKeyExisted]) {
        DLogTagWarn(kBLEKeyTag, @"安全钥匙和证书钥匙都不存在");
        return;
    }

    if ([[XPBLEHandlerManager manager] commuicateBleIsSendingBleCommand] && CTMediator.isE28) {
        DLogTagWarn(kBLEKeyTag, @"当前正在发送蓝牙车控指令,直接返回不做处理");
        return;
    }

    NSString *ifaaMsg = [CertKeyMessage getOneMessageWithVin:CTMediator.vin].message;
    DLogTagError_if([NSString isEmptyWithString:ifaaMsg], kBLEKeyTag, @"ifaaMsg is nil");
    __CHECK(![NSString isEmptyWithString:ifaaMsg])

    @weakify(self)
    NSMutableDictionary *params = [NSMutableDictionary dictionary];
    if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
        uint8_t controlId = [XPBLEControlIdFactory getControlId].unsignedShortValue;
        params[kBleKeyV3ControlIdKey] = @(controlId);
        NSMutableArray *dataArray = [NSMutableArray array];
        [dataArray addObject:@(cmd)];
        params[kBleKeyV3ControlDataKey] = [dataArray copy];
    } else {
        params[@"ifaa"] = ifaaMsg;
        params[@"cmd"] = @(cmd);
    }

    [XPBLEHandlerManager.manager sendRkeControlCertMessage:params complete:^(NSError * _Nonnull error) {
        if (error) {
            DLogTagError(kBLEKeyTag, @"%@",error);
            [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_back_to_homepage_tip", nil)];
        } else {
            DLogTagInfo(kBLEKeyTag, @"send ble command success");
            [self waitingForBiometricResults];
        }
    }];
}

