+ (void)sendQuickBeat{
    __CHECK([XPBLEHandlerManager.manager getCommuicateBLEConnectState] == XPBLEHanderConnectStateAuthorized)
    XPBLEParkingCommand cmd = XPBLEParkingCommandStop;
    [XPBLEHandlerManager.manager sendBleParkingHeartMessage:@{@"cmd":@(cmd),@"count":@(0)} complete:^(NSError * _Nullable error) {
        if (error) {
            DLogTagInfo(kBLEParkingTag,@"发送泊车指令cmd=%s,error=%@",StringFromXPBLEParkingCommand(cmd),error);
        } else {
            DLogTagInfo(kBLEParkingTag,@"发送泊车指令cmd=%s完成",StringFromXPBLEParkingCommand(cmd));
        }
    }];



}
