- (void)showFailToLockAlertWithError:(NSError *)error{
    //主线程处理UI
    dispatch_async(dispatch_get_main_queue(), ^{
        NSString *title = @"锁车失败，请检查";
        NSString *message = @"1. 请确保主驾无人\n2. 车门及前后盖已关闭\n3. 挡位置于P挡\n4. 车辆网络良好";
        if([error.userInfo[@"code"] integerValue] == MQTTResponseCodeSomeoneIsControlingCar){
            title = error.userInfo[NSLocalizedFailureReasonErrorKey];
            message = nil;
