281	- (void)checkIsDeleteSuccessAfterDoorIsLocked {
282	    self.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
283	    self.step2View.sLabel.text = @"s";
284	    self.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
285	    self.step3View.sLabel.text = @"s";
286	    __weak typeof(self) weakSelf = self;
287	    self.secondsTimer = [NSTimer bk_scheduledTimerWithTimeInterval:1 block:^(NSTimer *timer) {
288	        weakSelf.seconds--;
289	        weakSelf.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
290	        weakSelf.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
291	        if(weakSelf.seconds <= 0) {
292	            [weakSelf.secondsTimer invalidate];
293	            weakSelf.secondsTimer = nil;
294	            if(!weakSelf.isDeleteSuccess) {
295	                DLogTagInfo(kBLEKeyTag, @"解除授权%ld秒已到，未成功，跳转到失败页面", (long)kDeleteDuration);
296	                [weakSelf goToFailPageWithTips:@"抱歉发生了错误，请稍后重试"];
297	            }
298	        }
299	    } repeats:YES];
300	}
